@js:
pageNums = JSON.parse(result).data.pageInfos.length;
list = []
ua = "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/131.0.6778.140 Safari/537.36"
headers = {"User-Agent": ua}
option = {"headers": headers}
for (i = 0; i < pageNums; i++) {
    response = java.ajax(chapter.url + `/page?pageNum=${i + 1}` + ',' + JSON.stringify(option));
    img = '<img src="' + JSON.parse(response).data.url + '"/>'
    list.push(img)
}
html = list.join("\n");
html
